export const GENERATED_QUIZZES: QuizItem[] = [
  // ── en (20 items) ──
  { id: "q-en-a1-gemini-1-mqsalqbi", question: "She ___ a teacher.", options: ["am","is","are","be"], answer: 1, explain: "We use 'is' with singular subjects like 'she', 'he', and 'it' in the present simple tense of the verb 'to be'.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-2-mqsalqbi", question: "I have ___ orange.", options: ["a","an","the","some"], answer: 1, explain: "We use 'an' before words that start with a vowel sound (a, e, i, o, u) like 'orange'.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-3-mqsalqbi", question: "The keys are ___ the table.", options: ["in","on","at","for"], answer: 1, explain: "'On' is used to describe something that is physically resting on a surface, like a table.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-4-mqsalqbi", question: "There are three ___ in the park.", options: ["tree","trees","tree's","treeing"], answer: 1, explain: "When there is more than one of something, we use the plural form of the noun. For 'tree', the plural is 'trees'.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-5-mqsalqbi", question: "They ___ to school every day.", options: ["go","goes","going","went"], answer: 0, explain: "For plural subjects like 'they' and 'we', we use the base form of the verb 'go' in the present simple tense.", language: "en", level: "A1" },
  { id: "q-en-a2-gemini-1-mqsam0dy", question: "I ___ to Paris last year.", options: ["have been","went","go","gone"], answer: 1, explain: "We use the past simple tense for actions that happened at a specific time in the past, indicated here by 'last year'.", language: "en", level: "A2" },
  { id: "q-en-a2-gemini-2-mqsam0dy", question: "You ___ study hard if you want to pass the exam.", options: ["can","must","should","will"], answer: 2, explain: "We use 'should' to give advice or make a suggestion. It indicates that something is a good idea.", language: "en", level: "A2" },
  { id: "q-en-a2-gemini-3-mqsam0dy", question: "This book is ___ interesting than the last one.", options: ["more","most","many","much"], answer: 0, explain: "To form the comparative of long adjectives like 'interesting', we use 'more' before the adjective. 'Than' is used to compare two things.", language: "en", level: "A2" },
  { id: "q-en-a2-gemini-4-mqsam0dy", question: "She was late ___ the bus broke down.", options: ["but","and","because","so"], answer: 2, explain: "'Because' is a conjunction used to show the reason for something. The bus breaking down is the reason she was late.", language: "en", level: "A2" },
  { id: "q-en-a2-gemini-5-mqsam0dy", question: "Have you ever ___ sushi?", options: ["ate","eat","eaten","eating"], answer: 2, explain: "For the present perfect tense, we use 'have/has' followed by the past participle of the verb. The past participle of 'eat' is 'eaten'.", language: "en", level: "A2" },
  { id: "q-en-b1-gemini-1-mqsambqg", question: "I ___ to Paris last summer, but I ___ the Eiffel Tower yet.", options: ["went, haven't visited","have gone, didn't visit","was going, am not visiting","go, don't visit"], answer: 0, explain: "We use the past simple for a completed action at a specific time in the past ('last summer'). We use the present perfect for an action that started in the past and continues up to the present, or for an experience that has happened at some unspecified time before now, often with 'yet'.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-2-mqsambqg", question: "If I ___ a million dollars, I ___ around the world.", options: ["had, would travel","have, will travel","had, travel","would have, travelled"], answer: 0, explain: "This is a second conditional sentence, used for hypothetical or imaginary situations in the present or future. The structure is 'If + past simple, would + base form of the verb'.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-3-mqsambqg", question: "He told me that he ___ very busy the previous day.", options: ["had been","was","is","has been"], answer: 0, explain: "When reporting speech, if the reporting verb (told) is in the past, the verb in the reported clause usually shifts back one tense. 'I was busy' (past simple) becomes 'he had been busy' (past perfect).", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-4-mqsambqg", question: "That's the restaurant ___ we had dinner last week.", options: ["where","which","who","when"], answer: 0, explain: "We use 'where' as a relative pronoun to refer to a place. It introduces a relative clause that gives more information about the location.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-5-mqsambqg", question: "The famous painting ___ by a thief last night.", options: ["was stolen","stole","is stealing","has stolen"], answer: 0, explain: "This sentence uses the passive voice because the subject (the painting) is receiving the action, not performing it. The past simple passive is formed with 'was/were + past participle'.", language: "en", level: "B1" },
  { id: "q-en-b2-gemini-1-mqsamm44", question: "If I had studied harder in college, I ___ a more fulfilling career now.", options: ["would have had","would have","would be having","had had"], answer: 2, explain: "This is a mixed conditional, combining a past unreal condition ('If I had studied') with a present unreal result ('I would be having'). It describes how a past action would affect the present situation.", language: "en", level: "B2" },
  { id: "q-en-b2-gemini-2-mqsamm44", question: "It is essential that every student ___ their assignment on time.", options: ["submits","submit","submitted","will submit"], answer: 1, explain: "The subjunctive mood is used after expressions of necessity, importance, or urgency, such as 'It is essential that...'. In this structure, the verb takes its base form, regardless of the subject's number.", language: "en", level: "B2" },
  { id: "q-en-b2-gemini-3-mqsamm44", question: "The new policy ___ to significantly improve employee morale.", options: ["is expected","expects","has expected","will expect"], answer: 0, explain: "This sentence uses an advanced passive construction with a reporting verb. When the subject of the main clause is the entity being reported on, the passive voice is typically used, for example, 'The policy is expected to...'", language: "en", level: "B2" },
  { id: "q-en-b2-gemini-4-mqsamm44", question: "___ she wanted for her birthday was a new camera.", options: ["That","What","Which","It"], answer: 1, explain: "This is a 'what' cleft sentence, used to emphasize a particular piece of information. 'What' acts as a pronoun meaning 'the thing that'.", language: "en", level: "B2" },
  { id: "q-en-b2-gemini-5-mqsamm44", question: "She didn't answer her phone; she ___ asleep.", options: ["must have been","should be","might be","had to be"], answer: 0, explain: "'Must have been' is used to express a strong deduction or certainty about a past event, based on available evidence. In this case, not answering the phone leads to the strong conclusion that she was asleep.", language: "en", level: "B2" },
  // ── ja (85 items) ──
  { id: "q-ja-n2-gemini-1-mqzvvf2z", question: "彼は体調が悪い___、仕事に出かけた。", options: ["のに","にもかかわらず","ても","けど"], answer: 1, explain: "「〜にもかかわらず」means \"despite\" or \"even though\" and expresses that something happened contrary to expectations, often in a more formal context than 「のに」.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-2-mqzvvf2z", question: "多くの困難があった___、その計画は成功に終わった。", options: ["のだが","だから","にもかかわらず","なので"], answer: 2, explain: "「〜にもかかわらず」is used to indicate that something happened or proceeded despite a hindering factor, implying a surprising or unexpected outcome.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-3-mqzvvf2z", question: "天候不順___、収穫量は例年並みだった。", options: ["けれども","なのに","だがしかし","にもかかわらず"], answer: 3, explain: "「〜にもかかわらず」connects a cause or condition with a result that is contrary to what would normally be expected. It can connect nouns/na-adjectives directly or with 「であるにもかかわらず」.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-4-mqzvvf2z", question: "遅い時間であった___、彼は快く相談に応じてくれた。", options: ["として","だけあって","にもかかわらず","からといって"], answer: 2, explain: "「〜にもかかわらず」is used when an action or state occurs contrary to what one would expect from the preceding condition. In this case, despite it being late, he kindly responded.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-5-mqzvvf2z", question: "お忙しい___、大変恐縮ですが、少々お時間をいただけますでしょうか。", options: ["時に","ところを","際に","中で"], answer: 1, explain: "「〜ところを」is used to express an apology or gratitude when intruding upon someone's state or situation, often in formal contexts. Here, it means \"while you are busy.\"", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-6-mqzvvf2z", question: "夜遅くお休みの___、お電話してしまい、申し訳ございません。", options: ["間に","せいで","ときに","ところを"], answer: 3, explain: "「〜ところを」is a formal expression used when you apologize for disturbing someone during a specific state or action, such as being asleep.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-7-mqzvvf2z", question: "先生がご指導されている___、誠に恐縮ですが、少しお伺いしたいことがあります。", options: ["最中に","ために","ときには","ところを"], answer: 3, explain: "「〜ところを」is used when you interrupt or intrude upon someone's ongoing action or state, often accompanied by an apology or request.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-8-mqzvvf2z", question: "大変お困りの___、微力ながらお手伝いさせていただけませんか。", options: ["状況を","状態に","ところを","事態を"], answer: 2, explain: "「〜ところを」is used to express sympathy or an offer of help when someone is in a difficult situation. It indicates intervening at that specific moment.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-9-mqzvvf2z", question: "彼は宿題をやり___、遊びに行ってしまった。", options: ["きりで","とおりに","っぱなしで","ままで"], answer: 2, explain: "「〜っぱなし」means \"leaving something in a state\" or \"keeping on doing something,\" often implying negligence or a continuous, uncontrolled action. Here, it means \"leaving the homework unfinished.\"", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-10-mqzvvf2z", question: "エアコンをつけ___寝てしまい、風邪をひいてしまった。", options: ["たままで","ておくまま","っぱなしで","終わったまま"], answer: 2, explain: "「〜っぱなし」indicates that an action was left in its current state, often with a negative nuance of carelessness or neglect. Here, the air conditioner was left on.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-11-mqzvvf2z", question: "水を出し___にしないでください。もったいないですよ。", options: ["だけ","きり","っぱなし","ままで"], answer: 2, explain: "「〜っぱなし」is used to describe leaving something in an undesirable or careless state, such as leaving the water running.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-12-mqzvvf2z", question: "長時間立ち___の仕事で、足が棒のようになってしまった。", options: ["きり","っぱなし","つづけ","たまま"], answer: 1, explain: "「〜っぱなし」can also indicate that an action continued without interruption for a long time, often leading to a negative consequence like fatigue.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-13-mqzvvf2z", question: "彼女の言葉には、どこか皮肉___響きがあった。", options: ["らしい","ふうな","めいた","のような"], answer: 2, explain: "「〜めく」attaches to nouns to indicate \"to show signs of,\" \"to have the appearance of,\" or \"to be tinged with.\" 「皮肉めいた」means \"tinged with sarcasm.\"", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-14-mqzvvf2z", question: "街にはもう春___雰囲気が漂い始めている。", options: ["らしい","っぽい","のような","めいた"], answer: 3, explain: "「〜めく」is used to describe something taking on the characteristics or atmosphere of the noun it's attached to. Here, the town is beginning to feel like spring.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-15-mqzvvf2z", question: "彼の笑顔はいつも謎___で、本心が読めない。", options: ["のようで","らしいので","っぽいので","めいていて"], answer: 3, explain: "「〜めく」is used to describe something having the quality or characteristic of the noun. 「謎めいて」means \"mysterious-looking\" or \"having a mysterious air.\"", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-16-mqzvvf2z", question: "その話はあまりにも嘘___、誰も信じなかった。", options: ["のようで","めいていて","っぽいので","らしいので"], answer: 1, explain: "「〜めく」can be used to describe something that strongly appears to be a certain way, even if it's not explicitly stated. 「嘘めいた」means \"seeming like a lie.\"", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-17-mqzvvf2z", question: "京都へ旅行する___、金閣寺はぜひ訪れるべきだ。", options: ["と","ば","なら","たら"], answer: 2, explain: "「〜なら」is often used to state a condition or topic, and then offer advice or a suggestion related to that condition. It functions like \"if it's about X, then Y.\"", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-18-mqzvvf2z", question: "この本に興味がある___、図書館で借りられますよ。", options: ["れば","だったら","のなら","と"], answer: 2, explain: "「〜なら」is used to provide information or a suggestion based on the listener's stated or implied interest or situation. 「〜のなら」emphasizes the premise.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-19-mqzvvf2z", question: "もし分からないことが___、遠慮なく質問してください。", options: ["あれば","あったら","あると","あるのなら"], answer: 3, explain: "「〜のなら」is a conditional form often used when giving advice or making a request based on a specific situation or premise.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-20-mqzvvf2z", question: "田中さんのスケジュール___、秘書に確認するのが一番です。", options: ["ならば","となると","とすれば","でしたら"], answer: 3, explain: "「〜でしたら」is the polite form of 「〜なら」, used to introduce a topic and then provide related information, advice, or a suggestion.", language: "ja", level: "N2" },
  { id: "q-ja-n3-gemini-1-mqzvyijj", question: "毎日、日本語のニュースを聞く___。", options: ["ようにしています","ことになります","てしまいます","ばするほど"], answer: 0, explain: "「〜ようにする」 expresses a conscious effort to establish a habit or an action. Here, it means 'I make an effort to listen to Japanese news every day'.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-2-mqzvyijj", question: "急な出張で、来週の会議には出席できない___。", options: ["ようにしました","ことになりました","てしまいました","ばならないほど"], answer: 1, explain: "「〜ことになる」 indicates that something has been decided or arranged, often by circumstances or an external party, or that it turned out that way. Here, it means 'It has been decided that I cannot attend...'", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-3-mqzvyijj", question: "うっかり大事な書類を会社に忘れ___。", options: ["てしまいました","てなりません","たところです","てあげます"], answer: 0, explain: "「〜てしまう」 indicates that an action has been completed, often with a sense of regret, finality, or thoroughness. Here, it conveys regret about forgetting the documents.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-4-mqzvyijj", question: "子供が誤って時計を___。", options: ["壊れた","壊した","壊れて","壊させて"], answer: 1, explain: "「壊す (kowasu)」 is a transitive verb meaning 'to break something'. Since the child is the agent of the action, the transitive form is correct.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-5-mqzvyijj", question: "日本語は勉強すれば___、面白くなります。", options: ["するほど","すればするほど","するならばほど","するばかりほど"], answer: 0, explain: "「〜ば〜ほど」 means 'the more... the more...'. The pattern is Verb (ば form) + Verb (plain form) + ほど.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-6-mqzvyijj", question: "彼は初めて日本に来た___、日本語がとても上手だ。", options: ["にしては","にとって","として","に対して"], answer: 0, explain: "「〜にしては」 expresses surprise or a feeling that something is contrary to expectations, considering the given condition. Here, it means 'for someone who came to Japan for the first time...'", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-7-mqzvyijj", question: "部長はもう___になりましたか。", options: ["お帰り","ご帰り","お帰りする","帰る"], answer: 0, explain: "「お/ご〜になる」 is a polite expression used to show respect for the actions of others. 「お帰りになる」 is an honorific way to say 'to return'.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-8-mqzvyijj", question: "寝る前に必ず歯を磨く___。", options: ["ことになりました","てしまいました","ようにしています","ばかりです"], answer: 2, explain: "「〜ようにする」 indicates making a conscious effort to do something regularly or establish a habit. Here, it means 'I make sure to brush my teeth before bed'.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-9-mqzvyijj", question: "来月、新しいプロジェクトのリーダーを担当する___。", options: ["ようにします","ことになりました","てしまいます","ばしますほど"], answer: 1, explain: "「〜ことになる」 indicates that something has been decided or arranged, often by an external party or circumstances. Here, it means 'It has been decided that I will be in charge...'", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-10-mqzvyijj", question: "あの本は面白くて、一晩で全部読ん___。", options: ["でしまいました","でください","でいます","でありました"], answer: 0, explain: "「〜てしまう」 indicates that an action has been completed, often with a sense of thoroughness, speed, or regret. Here, it expresses completing the book quickly.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-11-mqzvyijj", question: "重い荷物を棚に___。", options: ["上がった","上げた","上がる","上げられた"], answer: 1, explain: "「上げる (ageru)」 is a transitive verb meaning 'to raise/lift something'. Since there is a direct object (荷物), the transitive form is correct.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-12-mqzvyijj", question: "勉強すれば___、頭がよくなります。", options: ["するほど","したほど","すればするほど","するならほど"], answer: 0, explain: "「〜ば〜ほど」 expresses a proportional relationship: 'the more... the more...'. The second verb should be in the plain form followed by ほど.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-13-mqzvyijj", question: "このレストランは値段が安い___、料理がとても美味しい。", options: ["にしては","にとって","として","にかけては"], answer: 0, explain: "「〜にしては」 is used to express a disparity between an expectation and reality. Here, it means 'for its cheap price, the food is very delicious'.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-14-mqzvyijj", question: "何か___ことはありますか。", options: ["お手伝いする","お手伝いになる","お手伝い","ご手伝い"], answer: 0, explain: "「お/ご〜する」 is a humble expression used to show respect by humbly referring to one's own actions towards someone. 「お手伝いする」 means 'to help (humbly)'.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-15-mqzvyijj", question: "遅刻しない___、家を早く出る。", options: ["ことになりました","ようにしています","てしまいます","ばかりです"], answer: 1, explain: "「〜ようにする」 is used to express the effort one makes to achieve a goal or state. Here, it means 'I make sure to leave home early so as not to be late'.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-16-mqzvyijj", question: "来月、引っ越す___。", options: ["ようにしました","ことになりました","てしまいました","ばしますほど"], answer: 1, explain: "「〜ことになる」 indicates that something has been decided, arranged, or is a consequence of circumstances. Here, it means 'It has been decided that I will move next month'.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-17-mqzvyijj", question: "新しいパソコンのデータ、全部消え___。", options: ["てしまいました","てあげます","ていました","ていましたか"], answer: 0, explain: "「〜てしまう」 is used to express that an action has been completed, often with a sense of regret, finality, or even shock. Here, it conveys the regret/shock of data being completely erased.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-18-mqzvyijj", question: "窓が風で急に___。", options: ["閉めた","閉まった","閉める","閉められた"], answer: 1, explain: "「閉まる (shimaru)」 is an intransitive verb meaning 'to close by itself'. Since the window closed due to wind, the intransitive form is appropriate.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-19-mqzvyijj", question: "休日は長ければ___、嬉しいです。", options: ["長いほど","長ければ長いほど","長くほど","長かったほど"], answer: 0, explain: "「〜ば〜ほど」 means 'the more... the more...'. For adjectives, it's (い-adjective ば form) + (い-adjective plain form) + ほど.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-20-mqzvyijj", question: "お客様、何か___がありますか。", options: ["ご質問","お質問","ご質問になる","質問"], answer: 0, explain: "「ご〜」 is used as a polite prefix for certain nouns, especially those of Chinese origin, to show respect to the listener or person being referred to. 「ご質問 (goshitsumon)」 means 'your question'.", language: "ja", level: "N3" },
  { id: "q-ja-n4-gemini-1-mqzvsi0z", question: "先週、新しい本を___。", options: ["買って","買います","買う","買った"], answer: 3, explain: "The sentence describes an action completed in the past (先週, last week). The た-form (買った) is used for plain past tense verbs.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-2-mqzvsi0z", question: "私は漢字を___ことができます。", options: ["書く","書いて","書き","書いた"], answer: 0, explain: "To express ability ('can do'), the dictionary form of the verb (書く) is used before ことができます.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-3-mqzvsi0z", question: "彼は今、コーヒーを___います。", options: ["飲む","飲み","飲んで","飲んだ"], answer: 2, explain: "The ている form (飲んでいます) indicates an action that is currently ongoing. '飲んで' is the te-form of 飲む.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-4-mqzvsi0z", question: "もし時間が___、映画を見に行きませんか。", options: ["あるなら","あれば","あったと","あると"], answer: 1, explain: "The ば conditional form (あれば) is often used for general conditions or to suggest a possibility, fitting the context of inviting someone if time permits.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-5-mqzvsi0z", question: "ドアを___、猫が外に飛び出しました。", options: ["開けると","開けば","開けたら","開けても"], answer: 2, explain: "The たら conditional form (開けたら) is used here to describe a sequential action (opening the door) followed by an unexpected or observed result (the cat jumping out).", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-6-mqzvsi0z", question: "毎日運動___、健康になります。", options: ["すると","すれば","したら","しては"], answer: 1, explain: "The ば conditional form (すれば) is used to express a general or logical condition, meaning 'if you exercise every day, you will become healthy'.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-7-mqzvsi0z", question: "冬になる___、雪が降ります。", options: ["たら","と","ば","ても"], answer: 1, explain: "The と conditional form (と) is used for natural consequences or things that always happen when a certain condition is met, like snow falling in winter.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-8-mqzvsi0z", question: "私はこの歌を___ことがあります。", options: ["歌って","歌う","歌います","歌った"], answer: 3, explain: "The た-form followed by ことがあります (歌ったことがあります) is used to express past experiences, meaning 'I have sung this song before'.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-9-mqzvsi0z", question: "部屋の窓が___います。", options: ["開ける","開けて","開いた","開いて"], answer: 3, explain: "The ている form (開いています) is used here to describe a state resulting from an action, meaning 'the window is open'.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-10-mqzvsi0z", question: "寝る___、歯を磨きます。", options: ["前には","前に","前で","前から"], answer: 1, explain: "The phrase 〜前に (〜する前に) means 'before doing 〜'. Here, it means 'before sleeping'.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-11-mqzvsi0z", question: "ここでタバコを___ください。", options: ["吸わないで","吸いません","吸わない","吸うな"], answer: 0, explain: "The ないでください form (吸わないでください) is used to politely ask someone not to do something.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-12-mqzvsi0z", question: "宿題を___なりません。", options: ["しなければ","しては","するなら","するべく"], answer: 0, explain: "The phrase 〜なければなりません (しなければなりません) means 'must do' or 'have to do', expressing obligation.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-13-mqzvsi0z", question: "昨日の試験はとても___。", options: ["難しかった","難しい","難しくない","難しくなる"], answer: 0, explain: "The sentence describes the state of the exam yesterday, so the past tense of the i-adjective (難しかった) is required.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-14-mqzvsi0z", question: "毎日、会社に___。", options: ["行く","行って","行きます","行った"], answer: 2, explain: "The です/ます form (行きます) is the polite present/future tense form of a verb, suitable for describing a daily routine in a polite context.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-15-mqzvsi0z", question: "あの人はピアノを___ことができます。", options: ["弾く","弾いて","弾いた","弾き"], answer: 0, explain: "To express ability, the dictionary form of the verb (弾く) is used before ことができます.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-16-mqzvsi0z", question: "このボタンを___と、電気がつきます。", options: ["押す","押して","押せば","押したら"], answer: 0, explain: "The と conditional form (押すと) indicates that when you push the button, the light will automatically turn on as a natural consequence.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-17-mqzvsi0z", question: "疲れた___、少し休憩しましょう。", options: ["と","ば","から","ら"], answer: 3, explain: "The たら conditional form (疲れたら) is used here to suggest an action (taking a break) based on a condition (being tired).", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-18-mqzvsi0z", question: "よく勉強___、いい点数が取れますよ。", options: ["すれば","すると","したら","しては"], answer: 0, explain: "The ば conditional (すれば) is used to express a general truth or advice: 'If you study hard, you'll get good grades.'", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-19-mqzvsi0z", question: "彼は何も___で、帰ってしまいました。", options: ["言わない","言わず","言いません","言わなかった"], answer: 1, explain: "The 〜ずに (言わずに) form, which is the negative te-form without で, means 'without doing something'. It is often contracted to 〜ず in more formal or literary contexts, but here 言わず is the most natural fit for 'without saying anything'.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-20-mqzvsi0z", question: "あの店はもう___しまいました。", options: ["閉まる","閉めて","閉まって","閉まった"], answer: 2, explain: "The てしまう form (閉まってしまいました) indicates that an action has been completed, often with a sense of regret or finality. 閉まる is an intransitive verb, so 閉まっている indicates a state of being closed, and 閉まってしまいました indicates it has become closed.", language: "ja", level: "N4" },
  { id: "q-ja-n5-gemini-1-mqsas2qm", question: "私は毎日、学校へ___。", options: ["行きます","行って","行かない","行きた"], answer: 0, explain: "The です/ます form (polite present affirmative) is used to state regular activities or habits, such as going to school daily.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-2-mqsas2qm", question: "これ___私の本です。", options: ["が","は","を","で"], answer: 1, explain: "The particle 'は' marks the topic of the sentence. Here, 'これ' (this) is being introduced as the topic of discussion.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-3-mqsas2qm", question: "私はリンゴ___食べます。", options: ["が","を","に","で"], answer: 1, explain: "The particle 'を' marks the direct object of a transitive verb. 'リンゴ' (apple) is the object being eaten by the subject.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-4-mqsas2qm", question: "私は毎日７時___起きます。", options: ["を","と","に","へ"], answer: 2, explain: "The particle 'に' is used to specify a particular point in time when an action occurs, such as a specific hour.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-5-mqsas2qm", question: "私はレストラン___食事をします。", options: ["へ","と","で","に"], answer: 2, explain: "The particle 'で' indicates the place where an action takes place. Here, 'レストラン' (restaurant) is where the action of eating occurs.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-6-mqsas2qm", question: "私は日本___行きます。", options: ["で","に","へ","と"], answer: 2, explain: "The particle 'へ' (pronounced 'e') indicates the direction or destination of movement. It signifies going towards Japan.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-7-mqsas2qm", question: "ちょっと待って___。", options: ["ください","います","ました","たい"], answer: 0, explain: "The て-form of a verb followed by 'ください' is used to make a polite request or command.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-8-mqsas2qm", question: "私はコーヒーを___。", options: ["飲みます","飲みません","飲んで","飲んだ"], answer: 1, explain: "The negative form of a verb in です/ます style (e.g., 飲みません) is used to express that an action is not performed.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-9-mqsas2qm", question: "誰___いますか。", options: ["は","を","が","で"], answer: 2, explain: "The particle 'が' marks the subject of a question when the subject itself is unknown or being identified, as in 'Who is there?'", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-10-mqsas2qm", question: "私は友達___映画を見ました。", options: ["と","へ","から","まで"], answer: 0, explain: "The particle 'と' is used to indicate that an action is done 'with' someone, such as watching a movie with a friend.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-11-mqsas2qm", question: "授業は９時___始まります。", options: ["へ","まで","から","と"], answer: 2, explain: "The particle 'から' indicates the starting point in time or space. Here, it signifies that the class starts 'from' 9 o'clock.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-12-mqsas2qm", question: "授業は３時___終わります。", options: ["から","へ","と","まで"], answer: 3, explain: "The particle 'まで' indicates the ending point in time or space. Here, it means the class finishes 'until' 3 o'clock.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-13-mqsas2qm", question: "これ___私のペンです。", options: ["が","を","の","で"], answer: 2, explain: "The particle 'の' indicates possession or modifies a noun by another noun. Here, it shows that the pen belongs to '私' (me).", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-14-mqsas2qm", question: "毎日ご飯を___、学校に行きます。", options: ["食べます","食べた","食べて","食べない"], answer: 2, explain: "The て-form is used to connect two or more actions that happen in sequence, indicating that eating happens before going to school.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-15-mqsas2qm", question: "ここでタバコを___ください。", options: ["吸います","吸いません","吸わないで","吸って"], answer: 2, explain: "To politely ask someone not to do something, use the ない-form of the verb followed by 'でください'.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-16-mqsas2qm", question: "この本はとてもおもしろい___。", options: ["です","ました","あります","います"], answer: 0, explain: "To make an i-adjective polite in the present tense, you add 'です' after it. 'おもしろいです' means 'it is interesting'.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-17-mqsas2qm", question: "部屋___猫がいます。", options: ["で","を","に","から"], answer: 2, explain: "The particle 'に' is used with 'います' (for animate objects) to indicate the location where something exists.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-18-mqsas2qm", question: "机___本があります。", options: ["へ","を","で","に"], answer: 3, explain: "The particle 'に' is used with 'あります' (for inanimate objects) to indicate the location where something exists.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-19-mqsas2qm", question: "___、映画を見ました。", options: ["明日","今日","昨日","毎日"], answer: 2, explain: "'昨日' (yesterday) is the appropriate time expression for an action that happened in the past, as indicated by '見ました' (watched).", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-20-mqsas2qm", question: "___は静かです。", options: ["あそこ","ここ","いつ","どこ"], answer: 1, explain: "'ここ' means 'here' and is used to refer to the speaker's current location. The sentence states that 'here is quiet'.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-21-mqsas2qm", question: "私はコーヒー___好きです。", options: ["は","を","が","で"], answer: 2, explain: "When expressing likes or dislikes with adjectives like 好きです (suki desu), the particle 'が' is used to mark the object of liking.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-22-mqsas2qm", question: "このペン、___もいいですか。", options: ["使います","使って","使う","使わない"], answer: 1, explain: "The て-form followed by 'もいいですか' is used to ask for permission, meaning 'May I use this pen?'", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-23-mqsas2qm", question: "彼は学生___。", options: ["です","ました","います","あります"], answer: 0, explain: "'です' is used to make a noun polite in the present tense, indicating what something or someone is. '彼は学生です' means 'He is a student'.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-24-mqsas2qm", question: "私は駅___行きます。", options: ["で","を","と","に"], answer: 3, explain: "The particle 'に' indicates a specific destination or point of arrival. It signifies going to the station.", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-25-mqsas2qm", question: "部屋に誰も___。", options: ["います","いません","あります","ありません"], answer: 1, explain: "'いません' is the polite negative form of 'います' and is used to state the non-existence of animate beings, meaning 'There is no one in the room'.", language: "ja", level: "N5" },
  // ── zh (85 items) ──
  { id: "q-zh-hsk1-gemini-1-mqzvw4ym", question: "这是我___书。", options: ["了","的","吗","是"], answer: 1, explain: "“的” is used to show possession, similar to \"'s\" in English. Here, it indicates \"my book\".", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-2-mqzvw4ym", question: "我吃___饭。", options: ["吗","了","的","是"], answer: 1, explain: "“了” indicates the completion of an action. Here, it means \"I have eaten the meal\".", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-3-mqzvw4ym", question: "你是老师___？", options: ["是","了","吗","的"], answer: 2, explain: "“吗” is a question particle placed at the end of a declarative sentence to turn it into a yes/no question.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-4-mqzvw4ym", question: "他___医生。", options: ["吗","是","有","了"], answer: 1, explain: "“是” means \"to be\" and is used to link a subject with a noun or pronoun that identifies it. Here, \"He is a doctor.\"", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-5-mqzvw4ym", question: "我___一个妹妹。", options: ["吗","是","了","有"], answer: 3, explain: "“有” means \"to have\" or \"there is/are\". Here, it means \"I have a younger sister.\"", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-6-mqzvw4ym", question: "___是我的铅笔。", options: ["了","这","那","吗"], answer: 1, explain: "“这” means \"this\". It is used to refer to something close to the speaker.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-7-mqzvw4ym", question: "___是你的手机吗？", options: ["吗","这","了","那"], answer: 3, explain: "“那” means \"that\". It is used to refer to something further away from the speaker.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-8-mqzvw4ym", question: "我有五个___苹果。", options: ["的","本","个","杯"], answer: 2, explain: "“个” is a common measure word used for many common nouns, including apples.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-9-mqzvw4ym", question: "她买了三___书。", options: ["杯","个","本","了"], answer: 2, explain: "“本” is a measure word specifically used for books and other bound volumes.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-10-mqzvw4ym", question: "请给我一___水。", options: ["本","吗","个","杯"], answer: 3, explain: "“杯” is a measure word for cups or glasses of liquid.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-11-mqzvw4ym", question: "___是星期三。", options: ["吗","今天","明天","了"], answer: 1, explain: "“今天” means \"today\". It refers to the current day.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-12-mqzvw4ym", question: "我___去北京。", options: ["吗","的","明天","今天"], answer: 2, explain: "“明天” means \"tomorrow\". It refers to the day after today.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-13-mqzvw4ym", question: "她___衣服很漂亮。", options: ["吗","了","是","的"], answer: 3, explain: "“的” can be used after an adjective or descriptive phrase to modify a noun, similar to \"beautiful clothes\".", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-14-mqzvw4ym", question: "天气冷___。", options: ["吗","了","是","的"], answer: 1, explain: "“了” can also indicate a change of state or a new situation. Here, it means \"the weather has turned cold\" or \"it's cold now\".", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-15-mqzvw4ym", question: "你会说中文___？", options: ["的","吗","是","了"], answer: 1, explain: "“吗” is a question particle used to form a yes/no question at the end of a sentence.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-16-mqzvw4yn", question: "这___我的咖啡。", options: ["吗","有","了","是"], answer: 3, explain: "“是” means \"to be\" and is used to identify or describe something. Here, it means \"This is my coffee.\"", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-17-mqzvw4yn", question: "商店里___很多东西。", options: ["吗","是","了","有"], answer: 3, explain: "“有” can indicate existence, meaning \"there is/are\". Here, \"There are many things in the store.\"", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-18-mqzvw4yn", question: "___本书是你的吗？", options: ["吗","这","了","那"], answer: 1, explain: "“这” means \"this\" and is used to refer to something close to the speaker.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-19-mqzvw4yn", question: "教室里有十___学生。", options: ["的","本","个","杯"], answer: 2, explain: "“个” is a common measure word used for people.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-20-mqzvw4yn", question: "___晚上我不回家。", options: ["了","吗","今天","明天"], answer: 2, explain: "“今天” means \"today\". \"今天晚上\" refers to \"tonight\".", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk2-gemini-1-mqzvz1v6", question: "他想 ___ 这本书看完。", options: ["了","把","在","对"], answer: 1, explain: "The 把-construction is used to bring the object of the verb before the verb, emphasizing the result or disposal of the object. The structure is Subject + 把 + Object + Verb + Other Element.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-2-mqzvz1v6", question: "我昨天 ___ 一个新手机。", options: ["买","买着","买了","买过"], answer: 2, explain: "The particle 了 after a verb indicates the completion of an action. Here, it shows the action of buying is finished.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-3-mqzvz1v6", question: "这件衣服 ___ 漂亮，但是有点贵。", options: ["比较","最","很","非常"], answer: 0, explain: "比较 (bǐjiào) means 'relatively' or 'comparatively' and is often used before an adjective to soften or qualify it. It indicates a degree that is less than 'very' but more than 'a little'.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-4-mqzvz1v6", question: "他是班里学习 ___ 努力的学生。", options: ["比较","更","挺","最"], answer: 3, explain: "最 (zuì) is used before adjectives or adverbs to indicate the superlative degree, meaning 'most' or '-est'.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-5-mqzvz1v6", question: "___ 今天下雨，___ 我们不去公园了。", options: ["因为/所以","虽然/但是","如果/就","不但/而且"], answer: 0, explain: "因为 (yīnwèi) introduces the reason, and 所以 (suǒyǐ) introduces the result or consequence. Together, they form a cause-and-effect sentence structure.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-6-mqzvz1v6", question: "我 ___ 说一点儿汉语。", options: ["能","可以","会","应该"], answer: 2, explain: "会 (huì) indicates a learned skill or ability, meaning 'to know how to' or 'can'. Speaking a language is a learned skill.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-7-mqzvz1v6", question: "这儿太吵了，我 ___ 听不清你说什么。", options: ["会","能","可以","应该"], answer: 1, explain: "能 (néng) indicates a physical ability or a possibility under certain conditions. Here, it means 'to be able to' due to the noise.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-8-mqzvz1v6", question: "请问，我 ___ 坐这里吗？", options: ["可以","会","能","要"], answer: 0, explain: "可以 (kěyǐ) is used to ask for or grant permission, meaning 'may' or 'can'. It is a polite way to ask.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-9-mqzvz1v6", question: "你喜欢喝咖啡 ___ 茶？", options: ["和","或者","还是","跟"], answer: 2, explain: "还是 (háishì) is used in interrogative sentences (questions) to offer a choice between two or more options.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-10-mqzvz1v6", question: "周末我喜欢看电影 ___ 听音乐。", options: ["和","还是","跟","或者"], answer: 3, explain: "或者 (huòzhě) is used in declarative sentences (statements) to offer a choice between two or more options.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-11-mqzvz1v6", question: "他没 ___ 作业写完。", options: ["了","把","在","给"], answer: 1, explain: "The negative form of the 把-construction places 没 or 不 before 把. This sentence indicates the action was not completed.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-12-mqzvz1v6", question: "她吃 ___ 饭就去上班了。", options: ["了","着","过","会"], answer: 0, explain: "了 after a verb indicates the completion of an action. Here, it signals that finishing eating happened before going to work.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-13-mqzvz1v6", question: "他的中文说得 ___ 好。", options: ["最","更好","比较","非常"], answer: 2, explain: "比较 (bǐjiào) can also be used to make a mild comparison or to indicate something is 'relatively good' or 'quite good'.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-14-mqzvz1v6", question: "我 ___ 喜欢吃饺子。", options: ["比较","很","经常","最"], answer: 3, explain: "最 (zuì) can precede adjectives or adverbs to form the superlative. Here, it means 'I like dumplings the most'.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-15-mqzvz1v6", question: "我喜欢这个城市，___ 这里很干净，___ 人们也很友好。", options: ["所以/因为","因为/所以","虽然/但是","不但/而且"], answer: 1, explain: "The 因为...所以... structure connects a cause and its effect. 'Because [reason], therefore [result]'. The reason for liking the city is its cleanliness and friendly people.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-16-mqzvz1v6", question: "明天 ___ 下雨吗？", options: ["能","可以","会","应该"], answer: 2, explain: "会 (huì) can indicate a future possibility or prediction, meaning 'will' or 'likely to'. It asks about the likelihood of rain.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-17-mqzvz1v6", question: "商店关门了，我们 ___ 买东西了。", options: ["不会","不能","不可以","不想"], answer: 1, explain: "能 (néng) in its negative form, 不能, often means 'cannot' due to circumstances or lack of ability. Here, the store being closed prevents buying.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-18-mqzvz1v6", question: "我 ___ 用一下你的笔吗？", options: ["会","能","应该","可以"], answer: 3, explain: "可以 (kěyǐ) is the most common and polite way to ask for permission, meaning 'may I' or 'can I'.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-19-mqzvz1v6", question: "你想吃米饭、面条 ___ 包子？", options: ["和","或者","还是","也"], answer: 2, explain: "When asking a choice question, 还是 (háishì) is used to connect the options. It asks 'do you want A, B, or C?'", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-20-mqzvz1v6", question: "你可以坐地铁、公交车 ___ 出租车去。", options: ["还是","或者","和","也"], answer: 1, explain: "In a declarative sentence presenting choices, 或者 (huòzhě) is used to connect the options, meaning 'or'.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk3-gemini-1-mqsax1zp", question: "我的钱包______小偷偷走了。", options: ["把","被","让","给"], answer: 1, explain: "The sentence uses the passive voice, indicating that the wallet was stolen by someone. \"被\" is used to introduce the agent in a passive sentence.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-2-mqsax1zp", question: "请你______那本书给我。", options: ["送","拿","带来","把"], answer: 3, explain: "The \"把\" construction is used to move the object before the verb, emphasizing the result or effect of the action on the object. Here, it indicates the action of giving \"that book\" to \"me\".", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-3-mqsax1zp", question: "他太忙了，______吃饭的时间______没有。", options: ["连...都","不但...而且","虽然...但是","越来越...越"], answer: 0, explain: "\"连...都/也\" is used to emphasize an extreme case, meaning \"even...\". In this sentence, it emphasizes that he is so busy he doesn't even have time to eat.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-4-mqsax1zp", question: "学中文______有意思。", options: ["连","把","越来越","不但"], answer: 2, explain: "\"越来越\" indicates a trend of gradual change, meaning \"more and more\" or \"increasingly\". Here it means learning Chinese is becoming more and more interesting.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-5-mqsax1zp", question: "她______会说汉语，______会唱中文歌。", options: ["虽然...但是","连...都","不但...而且","越来越...越"], answer: 2, explain: "\"不但...而且\" is used to connect two clauses or phrases, meaning \"not only...but also\". It shows that she has two abilities.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-6-mqsax1zp", question: "______天气很冷，______他们还是出去玩了。", options: ["因为...所以","不但...而且","虽然...但是","如果...就"], answer: 2, explain: "\"虽然...但是\" is used to express a concession, meaning \"although...but\". It shows a contrast between the cold weather and their decision to go out.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-7-mqsax1zp", question: "______我搬到上海，我就爱上了这座城市。", options: ["直到","自从","于是","后来"], answer: 1, explain: "\"自从\" means \"ever since\" and indicates the starting point of an action or state that continues up to the present.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-8-mqsax1zp", question: "我等了他很长时间，______晚上十点他才回来。", options: ["自从","已经","直到","忽然"], answer: 2, explain: "\"直到\" means \"until\" and indicates the endpoint of an action or state.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-9-mqsax1zp", question: "我的自行车______人骑走了。", options: ["是","让","把","被"], answer: 3, explain: "\"被\" is used to form a passive sentence, indicating that the bicycle was ridden away by someone. \"让\" or \"给\" can also be used, but \"被\" is the most common passive marker.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-10-mqsax1zp", question: "请你______作业交给我。", options: ["马上","把","已经","正在"], answer: 1, explain: "The \"把\" construction is used here to place the object \"作业\" (homework) before the verb \"交\" (submit), emphasizing the action's effect on the homework.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-11-mqsax1zp", question: "这个字太难了，我______写不出来。", options: ["连","正在","已经","总是"], answer: 0, explain: "\"连...都/也\" emphasizes an extreme case. Here, \"连...都写不出来\" means \"can't even write (this character)\", highlighting its difficulty.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-12-mqsax1zp", question: "他的汉语说得______流利了。", options: ["只是","当然","越来越","不但"], answer: 2, explain: "\"越来越\" signifies a continuous increase or improvement, meaning his Chinese speaking ability is becoming more and more fluent.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-13-mqsax1zp", question: "他______喜欢打篮球，______喜欢踢足球。", options: ["虽然...但是","因为...所以","不但...而且","如果...就"], answer: 2, explain: "This structure means \"not only...but also\", indicating that he enjoys both basketball and football.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-14-mqsax1zp", question: "______他很努力，______成绩还是不太好。", options: ["连...都","不但...而且","虽然...但是","越来越"], answer: 2, explain: "\"虽然...但是\" is used to show a contrast or concession, meaning \"although he works hard, his grades are still not very good.\"", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-15-mqsax1zp", question: "______上次见面，我们已经三年没见了。", options: ["直到","自从","于是","后来"], answer: 1, explain: "\"自从\" indicates the starting point of a period or event, meaning \"ever since our last meeting, we haven't met for three years.\"", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-16-mqsax1zp", question: "他学习到很晚，______凌晨两点才睡觉。", options: ["自从","已经","直到","忽然"], answer: 2, explain: "\"直到\" specifies the time when an action or state ends, meaning \"he studied very late, not going to bed until 2 AM.\"", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-17-mqsax1zp", question: "那个问题______老师解释得很清楚。", options: ["把","对","被","给"], answer: 2, explain: "The sentence is in the passive voice, indicating that the question was explained clearly by the teacher. \"被\" introduces the agent of the action.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-18-mqsax1zp", question: "请你______窗户打开。", options: ["马上","把","已经","正在"], answer: 1, explain: "The \"把\" construction emphasizes the action of opening the window and its effect on the window itself.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-19-mqsax1zp", question: "他病得很重，______水______喝不下去。", options: ["连...都","不但...而且","虽然...但是","越来越...越"], answer: 0, explain: "\"连...都/也\" is used to emphasize an extreme situation, meaning \"he is so sick that he can't even drink water.\"", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-20-mqsax1zp", question: "天气______热了。", options: ["只是","当然","越来越","不但"], answer: 2, explain: "\"越来越\" indicates a continuous change or trend, meaning the weather is getting hotter and hotter.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-21-mqsax1zp", question: "这部电影______很有趣，______很有教育意义。", options: ["虽然...但是","因为...所以","不但...而且","如果...就"], answer: 2, explain: "\"不但...而且\" means \"not only...but also\", indicating that the movie is both interesting and educational.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-22-mqsax1zp", question: "______下雨了，______我们还是决定去公园。", options: ["连...都","不但...而且","虽然...但是","越来越"], answer: 2, explain: "This structure expresses a concession, meaning \"although it's raining, we still decided to go to the park.\"", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-23-mqsax1zp", question: "______他开始学汉语，就对中国文化产生了兴趣。", options: ["直到","自从","于是","后来"], answer: 1, explain: "\"自从\" marks the starting point of an action or state, meaning \"ever since he started learning Chinese, he has developed an interest in Chinese culture.\"", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-24-mqsax1zp", question: "我等了很久，______他打来电话我才放心。", options: ["自从","已经","直到","忽然"], answer: 2, explain: "\"直到\" indicates the point in time when an action or state finally occurs or ends, meaning \"I waited a long time; only when he called did I feel relieved.\"", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-25-mqsax1zp", question: "妈妈______我做的饭都吃完了。", options: ["被","让","给","把"], answer: 3, explain: "The \"把\" construction is used to show that the mother finished eating all the food I made, emphasizing the result of the action on the food.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk4-gemini-1-mqzvxis4", question: "___ 你同意，我们就开始这个项目。", options: ["如果","既然","与其","只有"], answer: 0, explain: "The structure \"如果...就...\" (rúguǒ...jiù...) is used to express a conditional relationship, meaning \"if...then...\". Here, it indicates that if you agree, then the project will start.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-2-mqzvxis4", question: "这道菜的味道真好，我很快就吃___ 了。", options: ["好","完","到","住"], answer: 1, explain: "The resultative complement \"完\" (wán) indicates the completion of an action. \"吃完了\" means that the action of eating has been completed.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-3-mqzvxis4", question: "___ 浪费时间看电视，___ 多读几本书。", options: ["如果...就","既然...就","与其...不如","因为...所以"], answer: 2, explain: "The structure \"与其...不如...\" (yǔqí...bùrú...) is used to express a preference, meaning \"rather than A, it's better to B\".", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-4-mqzvxis4", question: "我把作业写___ 了，现在可以出去玩了。", options: ["完","到","住","好"], answer: 3, explain: "The resultative complement \"好\" (hǎo) indicates that an action has been completed and the result is satisfactory or ready. \"写好了\" means the homework is finished and ready.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-5-mqzvxis4", question: "我的钥匙找不___ 了，你帮我找找好吗？", options: ["住","好","完","到"], answer: 3, explain: "The resultative complement \"到\" (dào) indicates the successful achievement of an action or goal. \"找不到\" means unable to find.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-6-mqzvxis4", question: "___ 他知道错了，你就原谅他吧。", options: ["如果","既然","与其","只要"], answer: 1, explain: "The structure \"既然...就...\" (jìrán...jiù...) is used to express a logical consequence based on a known premise, meaning \"since/given that...then...\".", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-7-mqzvxis4", question: "请你记___ 我的手机号码，下次联系我就方便了。", options: ["好","完","到","住"], answer: 3, explain: "The resultative complement \"住\" (zhù) can indicate holding firm, stopping, or remembering something firmly. \"记住\" means to remember something firmly and not forget it.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-8-mqzvxis4", question: "这幅画是___ 谁画的？", options: ["给","在","是","让"], answer: 2, explain: "The \"是...的\" (shì...de) construction is used to emphasize the time, place, manner, or agent of a past action. Here, it emphasizes \"who\" painted the picture.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-9-mqzvxis4", question: "如果下雨，我们___ 在家看电影。", options: ["就","才","却","都"], answer: 0, explain: "The particle \"就\" (jiù) often appears in the second clause of an \"如果...就...\" conditional sentence, indicating the consequence.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-10-mqzvxis4", question: "我的电脑___ 弟弟不小心弄坏了。", options: ["被","给","让","把"], answer: 2, explain: "The word \"让\" (ràng) can be used to form a passive sentence, indicating that the action was caused by someone or something, often with an undesirable outcome.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-11-mqzvxis4", question: "___ 你不喜欢吃这个，___ 我们可以点别的。", options: ["如果...就","与其...不如","既然...就","只有...才"], answer: 2, explain: "The structure \"既然...就...\" (jìrán...jiù...) expresses a logical consequence. Since you don't like it, then we can order something else.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-12-mqzvxis4", question: "我昨天买的衬衫___ 弄脏了，还没穿呢。", options: ["是","让","把","给"], answer: 1, explain: "Here, \"让\" (ràng) is used in a passive structure to indicate that the shirt got dirty, often implying it happened unintentionally or by some external factor.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-13-mqzvxis4", question: "这部电影我还没看___，你别剧透！", options: ["好","完","到","住"], answer: 1, explain: "The resultative complement \"完\" (wán) indicates the completion of an action. \"还没看完\" means the action of watching has not yet been completed.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-14-mqzvxis4", question: "___ 每天都努力学习，你的中文水平一定会提高。", options: ["既然","如果","不如","除非"], answer: 1, explain: "The structure \"如果...就...\" (rúguǒ...jiù...) is used to express a conditional relationship, meaning \"if...then...\". Here, if you study hard every day, your Chinese will improve.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-15-mqzvxis4", question: "这件礼物是___ 谁送给你的？", options: ["在","是","把","让"], answer: 1, explain: "The \"是...的\" (shì...de) construction emphasizes the agent (who) of a past action. The structure focuses on the detail of the gift-giving event.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-16-mqzvxis4", question: "___ 总是抱怨，___ 想办法解决问题。", options: ["如果...就","既然...就","与其...不如","因为...所以"], answer: 2, explain: "The structure \"与其...不如...\" (yǔqí...bùrú...) expresses a preference, meaning \"rather than always complaining, it's better to think of ways to solve the problem\".", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-17-mqzvxis5", question: "他因为太忙，忘记了那件事，___ 他的朋友很生气。", options: ["所以","如果","既然","让"], answer: 3, explain: "The word \"让\" (ràng) here means \"to make\" or \"to cause\", indicating that his forgetting caused his friend to be angry.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-18-mqzvxis5", question: "我昨天买的手机，今天早上就摔___ 了。", options: ["好","完","到","坏"], answer: 3, explain: "The resultative complement \"坏\" (huài) indicates that something is broken or damaged as a result of an action. \"摔坏了\" means it was broken by falling.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-19-mqzvxis5", question: "你___ 答应了别人，___ 要做到。", options: ["如果...就","既然...就","与其...不如","只有...才"], answer: 1, explain: "The structure \"既然...就...\" (jìrán...jiù...) expresses a logical consequence. Since you've promised others, then you must keep your word.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-20-mqzvxis5", question: "我们是___ 去年夏天认识的。", options: ["在","是","把","让"], answer: 1, explain: "The \"是...的\" (shì...de) construction is used to emphasize the time of a past action. Here, it emphasizes when they met.", language: "zh", level: "HSK4" },
];
